const row = $input.first()?.json;

if (!row || !row.uf) {
  return [{ json: {
    message: '⚠️ *ETL PNCP — sem execução hoje*\nO cron pode ter falhado. Verificar /tmp/pncp-etl.log no servidor.'
  }}];
}

const status_emoji = row.status === 'ok' ? '✅' : row.status === 'parcial' ? '⚠️' : '❌';
const hora = new Date(row.executado_em).toLocaleTimeString('pt-BR', {hour:'2-digit',minute:'2-digit'});

const msg = [
  `🏛️ *ETL PNCP — ${row.uf}* ${status_emoji}`,
  `📅 ${new Date().toLocaleDateString('pt-BR')} às ${hora}`,
  ``,
  `📦 Inseridas: *${row.inseridos}* licitações`,
  `🔁 Duplicadas: ${row.duplicados}`,
  `⚠️ Erros: ${row.erros}`,
  `⏱ Duração: ${row.duracao_seg}s`,
  ``,
  `🔗 Superset: http://192.168.1.9:3006`,
].join('\n');

return [{ json: { message: msg } }];
